#include <iostream>
#include <algorithm>
using namespace std;

const int MOD = 1000000007;

int N;
int edges[1000][1000];
int depth[1000];

void dfs(int cur, int from, int d) {

    depth[cur] = d;

    for (int i = 0; i < N; ++i) {
        if (edges[cur][i] && i != from) {
            dfs(i, cur, d + edges[cur][i]);
        }
    }
}

int ans[1000];

int main() {

    cin >> N;

    for (int i = 0; i < N - 1; ++i) {

        int a, b, l;

        cin >> a >> b >> l;

        --a;
        --b;

        edges[a][b] = l;

    }

    dfs(0, -1, 0);

    for (int i = 1; i < N; ++i) {

        ans[depth[i]] = (ans[depth[i]] + 1) % MOD;
    }

    for (int d = 1; d < N; ++d) {

        ans[d] = (ans[d - 1] + ans[d]) % MOD;
    }

    for (int i = 1; i < N; ++i) {

        cout << ans[depth[i] - 1] << endl;
    }

    return 0;
}

