```class Solution {
public:
    vector<vector<int>> threeSum(vector<int>& nums) {
        vector<vector<int> > ret;
        int len = nums.size();
        if (len < 3) {
            return ret;
        }
        sort(nums.begin(), nums.end());
        for (int i = 0; i < len - 2; i++) {
            int left = i + 1, right = len - 1;
            int sum = -nums[i];
            /*
            * 如果相加大于零表示最右边的值大了，所以右指针左移
            * 如果相加小于零表示最左边的值小了，所以左指针右移
            * */
            while (left < right) {
                while (left < right && (nums[left] + nums[right]) > sum) {
                    right--;
                }
                while (left < right && (nums[left] + nums[right]) < sum) {
                    left++;
                }
                if (left == right) {
                    break;
                }
                if (left < right) {
                    vector<int> temp(3);
                    temp[0] = nums[i];
                    temp[1] = nums[left];
                    temp[2] = nums[right];
                    ret.push_back(temp);
                    /*
                    * 如果相等则右指针左移直到当前值不等于之前的值
                    * 右指针左移是为了考虑重复的数据，因为数组是排好序的，所以重复的值肯定连续的
                    * */
