                        left++;
                    }
                }
            }
            /*
            * 如果相加等于零表示当前值小了，所以左指针右移，这样就不需要重复的数据了
            * */
            while (i < len - 1 && nums[i] == nums[i + 1]) {
                i++;
            }
        }
        return ret;
    }
};
