struct Node
{
    int val;
    int priority;
    std::vector<Node*> childs;
};


void AddChild(Node* root, int data, int priority)
{
    Node* child = new Node; // создаем пустой узел
    child->val = data; // задаем значение нового узла
    child->priority = priority;
    child->childs.clear(); // очищаем список дочерних узлов
    root->childs.push_back(child); // добавляем новый узел в список дочерних узлов корневого узла
}

void print(Node *node)
{
    // добавляем значение узла в консоль
