struct Node
{
    int priority;
    int val;
    Node* left;
    Node* right;
};

// функция для создания и добавления узла в дерево
void add_node(Node* root, int val, int priority)
{
    Node* tmp = new Node;
    tmp->val = val;
    tmp->priority = priority;
    tmp->right = tmp->left = nullptr;
    if (!root)
    {
        root = tmp;
        return;
    }
    if (priority > root->priority)
    {
        add_node(root->left, val, priority);
    }
    else
    {
        add_node(root->right, val, priority);
    }
}
// функция для упорядочивания дерева по приоритету (другим параметром будем пустой список узлов)
void sort_tree(Node* root, std::vector<Node> list)
{
    if (!root)
    {
        return;
    }
    // сортируем список узлов в словаре по приоритету
    list.push_back(*root);
    sort_tree(root->left, list);
    sort_tree(root->right, list);
    // проверяем каждый узел на правильность его положения в списке
    for (int i = 0; i < list.size(); i++)
    {
        for (int j = i + 1; j < list.size(); j++)
        {
            if (list[i].priority > list[j].priority)
            {
                Node tmp = list[i];
                list[i] = list[j];
                list[j] = tmp;
                break;
            }
        }
    }
    // формируем дерево из списков в порядке возрастания
    for (int i = 0; i < list.size(); i++)
    {
        root = nullptr;
        add_node(root, list[i].val, list[i].priority);
    }
}

