    Node* add(Node** root, int val, int priority)
{
    Node** temp = root;
    Node* newnode = new Node();
    newnode->val = val;
    newnode->priority = priority;
    newnode->left = newnode->right = newnode->parent = nullptr;

    if (*root == nullptr)
    {
        *root = newnode;
    }
    else
    {
        while (*temp != nullptr)
        {
            if (newnode->val >= (*temp)->val)
            {
                if ((*temp)->right == nullptr)
                {
                    (*temp)->right = newnode;
                    newnode->parent = *temp;
                    break;
                }
            }

            if (newnode->val < (*temp)->val)
            {
                if ((*temp)->left == nullptr)
                {
                    (*temp)->left = newnode;
                    newnode->parent = (*temp);
                    break;
                }
            }

            if (newnode->priority >= (*temp)->priority)
            {
                temp = &(*temp)->right;
            }

            if (newnode->priority < (*temp)->priority)
            {
                temp = &(*temp)->left;
            }
        }
    }

    if (*root != newnode)
    {
        Node* temp = (*root);
        std::vector<Node*> queue = {};
        while (temp->right != nullptr)
        {
            queue.push_back(temp);
            temp = temp->right;
            Node* temp2 = temp->left;
            while (temp2->right != nullptr)
            {
                queue.push_back(temp2);
                temp2 = temp2->right;
            }
        }
        queue.push_back(temp);
        for_each(queue.begin(), queue.end(), [&root](Node* node) {node->right = (*root)->left; });
        (*root)->left = nullptr;
    }

    return root;
}

