XmlHelper::XmlHelper(QObject *parent):QObject(parent) {
  qDebug() << "XmlHelper: create instance";
}

QString XmlHelper::loadXml(const QString &filename) {
  Q_UNUSED(filename)
  return "<XML/>";
}


bool XmlHelper::saveXmlTo(const QString &filename, const QString &xml) {
  QFile file(filename);
  if (!file.open(QIODevice::WriteOnly | QIODevice::Text | QIODevice::Truncate)) {
    qWarning() << "Unable to write to file: " << filename;
    return false;
  }

  QTextStream out(&file);
  out.setCodec("UTF-8");
  out << QString("\n<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n") << XmlHelper::xmlHeaderComment(xml);
  out << xml;
  file.close();

  return true;
}

QString XmlHelper::xmlHeaderComment(const QDomDocument &doc) {
  static bool headerCreated = false;
  if (!headerCreated) {
    headerCreated = true;
    QFile file(":/xml/HeaderComment.txt");
    if (file.open(QIODevice::ReadOnly | QIODevice::Text)) {
      QByteArray line = file.readLine();
      if (!line.isEmpty())
        return QString("\uFEFF") + QString(line);

      file.close();
    }
  }

  return QString();
}


QString XmlHelper::xpathValue(QDomNode node, const QString &xpath) {

  QXmlQuery query;
  query.setQuery(xpath);
  query.setLiteralBinding("document", QString::fromUtf8(node.toString().toLatin1()));
  query.evaluateTo(&node);
  if (!node.isNull()) {
    return node.toNodeValue();
  }
  return "";
}


void XmlHelper::saveXmlNodeAsDatabaseEntry(int tableId, QDomNode node) {
  QString sqlCmd;
  sqlCmd += QString("INSERT INTO node_data (node_id, tableid, tag, value) VALUES (%1, %2, '%3', '%4')") %
            XmlHelper::xpathValue(node, QString(1)).toUInt() % tableId %
            XmlHelper::xpathValue(node, QString(2)) % XmlHelper::xpathValue(node, QString(3)).trimmed(); 
  QSqlQuery sqlQuery;
  if (!sqlQuery.exec(sqlCmd)) {
    qWarning() << "XmlHelper: saveXmlNodeAsDatabaseEntry failed for NodeID: " << XmlHelper::xpathValue(node, QString(1))
              << ", SQL-ERROR: " << sqlQuery.lastError().text();
  }
}

void XmlHelper::saveXmlDocumentAsDatabaseEntry(int tableId, QDomDocument doc) {
  QDomNodeList nodes = doc.documentElement().childNodes();
  for (int i = 0; i < nodes.size(); ++i) {
    saveXmlNodeAsDatabaseEntry(tableId, nodes.at(i));
  }

}

