        public void Accept(InputState inputState)
        {
            PlayerInputManager input = (PlayerInputManager)inputState;

            if (resultsScreen.ResultsContainer.BlockedState != BlockState.None)
                return;

            if (ResultsInProgress)
                return;
            else if (resultsScreen.CurrentResult < 0 && results != null)
                return;

            foreach (OsuRuleset ruleset in possibleRetroRulesets)
            {
                if (!input?.HasAnyMod(mods.ToList()) ?? true)
                    play(ruleset);
                else
                {
                    foreach (OsuMod mod in mods)
                    {
                        if (input.SelectedMods.ContainsMod(mod))
                        {
                            play(ruleset.WithRuleset(ruleset.Ruleset.Value.WithMod(mod)));
                            break;
                        }
                    }
                }
            }
        }

        protected override void Dispose(bool isDisposing)
        {
            base.Dispose(isDisposing);

            if (isDisposing) resultsTimer?.Dispose();
        }

