    int getLevels(TreeNode treeRoot, int depth) {

            // This is how my recursion tree looks for level 4.
            // This is how my function calls treeRecursion

            // treeRecursion ( root left ( root left ) right ( root left ) left() ) ) 

           if (level <= treeRoot.val && treeRoot.left != null) { // level++ and go into the left subtree. 
               int newdepth = depth + 1;
               if (newdepth > treeArray.length) treeArray[depth] = treeRoot.left;
                  else  treeArray[newdepth] = treeRoot.left; 
               level = treeRoot.val + 1; 
               getLevels(treeRoot.left, newdepth);// Level incrementing is always in the left hand tree.
           }
           if (level <= treeRoot.val  && treeRoot.right != null) { 
               int newdepth = depth + 1;
               if (newdepth > treeArray.length) treeArray[depth] = treeRoot.right;
                  else treeArray[newdepth] = treeRoot.right; 
