object Minter{
  def addMaxMinter(minter:Set[MinterIndex]):Unit={
    for(m<-minter){
      if(max.contains(m)){
        var list=max(m)
        list=list.filter(i=>minter.contains(i))
        max(m)=list.toList
      }else{
        max(m)=minter.toList
      }
    }
  }
  def addMinMinter(minter:Set[MinterIndex]):Unit={
    for(m<-minter){
      if(min.contains(m)){
        var list=min(m)
        list=list.filter(i=>minter.contains(i))
        min(m)=list.toList
      }else{
        min(m)=minter.toList
      }
    }
  }
}

