/* Write reverse and rotation algorithm for queue.
 */
/**
1) The element from the 0th index of the queue and stored it to the array in the 1st index
    shift all the elements by one index, this make the que last element
    2) the stored array first element shift left to position 0 in the queue.
2) The element from the 0th index of the queue and stored it to the array in the 1st index
    shift all the elements by one index, this make the que last element
    2) the stored array first element shift left to position 0 in the queue.

*/
class Queue{
public:
    int arr[10];
    int front,end;
    Queue(){
        front=-1;
        end=-1;
    }
    void Push(int x);
    int Pop();
    void Reverse();
    void RightRotate(int num);
    void LeftRotate(int num);
};
void Queue::Push(int x)
{
    if(isFull())
    {
        cout<<"Queue Overflow\n";
        return ;
    }
    arr[++end]=x;
    if(front == -1)
        front = end;
    cout << "Insert "<<x<<" into queue\n";
}
void Queue::Pop(){
    if(front == -1 )
    {
        cout<<"Queue UnderOverFlow\n";
        return ;
    }
    arr[front] = 0;
    front++;
    cout << "Delete "<<arr[front]<<" from queue\n";
}
void Queue::Reverse()
{
   for(;front <= end ; front++)
    {
        int temp = arr[front];
        arr[front] = arr[end--];
        arr[end+1] = temp;
    }
    cout<<"Reversed\n";
    print();
}
void Queue:: LeftRotate(int num)
{
    if(num==0)
        return ;
    num %= (end-front+1);

    for(int i = 0; i < num; i++)
    {
        int temp = arr[front];
        for(int i = front; i <= end-1; i++)
        {
            arr[i]=arr[i+1];
            print();
        }
        if(end >= (front+num-1))
            arr[end-num+1]=temp;
        arr[end]=0;
    }
    cout<<"Left Rotation\n";
    print();
}
void Queue::RightRotate(int num)
{
    if(num==0)
        return ;
    num %= (end-front+1);

    for(int i = 0; i < num; i++)
    {
        int temp = arr[end];
        for(int i = end-1; i >=front; i--)
        {
            arr[i]=arr[i-1];
            print();
        }
        arr[front] = temp;
        front++;
    }
    cout<<"Right Rotation\n";
    print();

}
void Queue::print(){

    for(int i = 0; i <= end; i++)
        cout<<arr[i];
    cout<<"\n\n";
}

